// Parse the Claude API response
const response = $input.first().json;
const rawText = response.content[0].text;

let post;
try {
  post = JSON.parse(rawText);
} catch(e) {
  // Try to extract JSON if wrapped in code blocks
  const match = rawText.match(/\{[\s\S]*\}/);
  if (match) {
    post = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse Claude response as JSON: ' + rawText.substring(0, 200));
  }
}

// Validate required fields
const required = ['slug', 'title', 'category', 'sections', 'intro'];
for (const field of required) {
  if (!post[field]) throw new Error(`Missing required field: ${field}`);
}

// Format date
const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });
const isoDate = now.toISOString().split('T')[0];

// Build sections HTML
let sectionsHTML = '';
for (const section of post.sections) {
  sectionsHTML += `<h2>${section.h2}</h2>\n`;
  sectionsHTML += `<p>${section.body}</p>\n`;
  if (section.codeExample) {
    sectionsHTML += `<pre><code>${section.codeExample.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</code></pre>\n`;
  }
  if (section.tip) {
    sectionsHTML += `<div class="tip-box"><strong>💡 Pro Tip:</strong> ${section.tip}</div>\n`;
  }
}

// Unsplash image URL
const imgQuery = encodeURIComponent(post.heroImageQuery || 'database technology');
const heroImg = `https://source.unsplash.com/1200x420/?${imgQuery}`;

// Build the full HTML page
const html = `<!DOCTYPE html>
<html lang="en">
<head>
<script async src="https://www.googletagmanager.com/gtag/js?id=G-4WJPXKKQT0"></script>
