<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${post.title} | ilovedatabase</title>
<meta name="description" content="${post.metaDescription || post.title}">
<meta name="keywords" content="${post.keywords || ''}">
<meta name="author" content="ilovedatabase">
<link rel="canonical" href="https://ilovedatabase.com/blog/${post.slug}/">
<meta property="og:title" content="${post.title}">
<meta property="og:description" content="${post.metaDescription || post.title}">
<meta property="og:type" content="article">
<meta property="og:url" content="https://ilovedatabase.com/blog/${post.slug}/">
<meta property="og:image" content="${heroImg}">
<meta name="twitter:card" content="summary_large_image">
<meta name="robots" content="index, follow">
<script type="application/ld+json">{"@context":"https://schema.org","@type":"Article","headline":"${post.title}","description":"${post.metaDescription || ''}","datePublished":"${isoDate}","publisher":{"@type":"Organization","name":"ilovedatabase","url":"https://ilovedatabase.com"}}</script>
<link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@fortawesome/fontawesome-free@6.4.0/css/all.min.css">
<link rel="stylesheet" href="../../css/main.css">
<link rel="stylesheet" href="../../css/responsive.css">
<link rel="stylesheet" href="../../css/blog.css">
<style>
.post-hero{width:100%;max-height:420px;object-fit:cover;border-radius:12px;margin-bottom:2rem}
.post-body{max-width:780px;margin:0 auto;line-height:1.8}
