    <img src="${heroImg}" alt="${post.title}" class="post-hero" loading="eager" onerror="this.src='https://images.unsplash.com/photo-1544383835-bda2bc66a55d?w=1200&q=80'">
    <div class="post-body">
      <div class="article-meta">
        <span><i class="fas fa-tag"></i> ${post.category}</span>
        <span><i class="fas fa-calendar"></i> ${dateStr}</span>
        <span><i class="fas fa-clock"></i> ${post.readTime || 8} min read</span>
      </div>
      <h1>${post.title}</h1>
      <p>${post.intro}</p>
      ${sectionsHTML}
      <p><strong>Conclusion:</strong> ${post.conclusion || ''}</p>
      <p>Want to learn more? Explore our <a href="../../tutorials/index.html">free SQL tutorials</a> or <a href="../../blog/index.html">browse the blog</a> for more database content.</p>
    </div>
