return [
  {
    json: {
      slug: post.slug,
      title: post.title,
      category: post.category,
      date: isoDate,
      dateFormatted: dateStr,
      html: html,
      filePath: `blog/${post.slug}/index.html`,
      metaDescription: post.metaDescription
    }
  }
];

// Build the blog index update data
const post = $input.first().json;

// This node outputs the new post card HTML to be prepended to blog/index.html
const newCardHTML = `
<!-- AUTO-GENERATED POST: ${post.date} -->
<article class="post-card" data-auto-generated="true">
  <div class="post-image">
    <img src="https://source.unsplash.com/500x300/?database" alt="${post.title}" loading="lazy">
  </div>
  <div class="post-content">
    <div class="post-meta">
      <span class="category">${post.category}</span>
      <time datetime="${post.date}">${post.dateFormatted}</time>
    </div>
    <h3 class="post-title">
      <a href="/blog/${post.slug}/">${post.title}</a>
    </h3>
    <p class="post-excerpt">${post.metaDescription}</p>
    <div class="post-stats">
      <span><i class="fas fa-clock"></i> 8 min read</span>
      <span><i class="fas fa-star"></i> New</span>
    </div>
  </div>
</article>`;

return [
  {
    json: {
      ...post,
      blogCardHTML: newCardHTML
    }
  }
];

// Prepare binary HTML data for Google Drive upload
const post = $input.first().json;

// Convert HTML string to binary
const htmlBuffer = Buffer.from(post.html, 'utf-8');

return [
  {
    json: post,
    binary: {
      data: {
        data: htmlBuffer.toString('base64'),
        mimeType: 'text/html',
        fileName: `${post.slug}-${post.date}.html`
      }
    }
  }
];

