const apiResponse = $input.first().json;
const rawText = apiResponse.content[0].text;

let social;
try {
  social = JSON.parse(rawText);
} catch(e) {
  const match = rawText.match(/\{[\s\S]*\}/);
  social = match ? JSON.parse(match[0]) : { twitter: rawText, linkedin: rawText, instagram: rawText };
}

// Get the post data from earlier in the workflow
const postSlug = $('Build HTML Page').first().json.slug;
const postTitle = $('Build HTML Page').first().json.title;

return [
  {
    json: {
      twitter: social.twitter,
      linkedin: social.linkedin,
      instagram: social.instagram,
      postTitle,
      postSlug,
      postUrl: `https://ilovedatabase.com/blog/${postSlug}/`
    }
  }
];

// Log error and alert
const error = $input.first().json;
console.error('Blog generation failed:', JSON.stringify(error));
return [{ json: { error: 'Blog post generation failed', details: error, timestamp: new Date().toISOString() } }];
